function clean(value) {
  if (value === null || value === undefined || value === '') return 'Unknown';
  return String(value)
    .trim()
    .replace(/[\/\\:*?"<>|]/g, '-')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^[-.]+|[-.]+$/g, '');
}

function normalizeCurrency(value) {
  if (value === null || value === undefined || value === '') return 'Unknown';
  const result = String(value)
    .trim()
    .toUpperCase()
    .replace(/[^A-Z]/g, '');
  return result || 'Unknown';
}

function normalizeAmount(value) {
  if (value === null || value === undefined || value === '') return 'Unknown';

  let str = String(value).trim();

  str = str.replace(/\s+/g, '');
  str = str.replace(/'/g, '');
  str = str.replace(/[A-Za-z₣$€£¥]/g, '');

  if (str.includes('.') && str.includes(',')) {
    str = str.replace(/\./g, '').replace(',', '.');
  } else if (str.includes(',') && !str.includes('.')) {
    str = str.replace(',', '.');
  }

  str = str.replace(/[^0-9.-]/g, '');

  if (!str || str === '-' || isNaN(Number(str))) return 'Unknown';

  return Number(str).toFixed(2);
}

function normalizeDate(value) {
  if (value === null || value === undefined || value === '') return 'Unknown';

  let str = String(value).trim();

  if (!str || /^unknown$/i.test(str)) return 'Unknown';

  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;

  let m = str.match(/^(\d{1,2})[.\-/](\d{1,2})[.\-/](\d{4})$/);
  if (m) {
    const dd = m[1].padStart(2, '0');
    const mm = m[2].padStart(2, '0');
    const yyyy = m[3];
    return `${yyyy}-${mm}-${dd}`;
  }

  const months = {
    jan: '01', january: '01',
    feb: '02', february: '02',
    mar: '03', march: '03', märz: '03', maerz: '03',
    apr: '04', april: '04',
    may: '05', mai: '05',
    jun: '06', june: '06', juni: '06',
    jul: '07', july: '07', juli: '07',
    aug: '08', august: '08',
    sep: '09', sept: '09', september: '09',
    oct: '10', october: '10', okt: '10', oktober: '10',
    nov: '11', november: '11',
    dec: '12', december: '12', dez: '12', dezember: '12'
  };

  const lower = str.toLowerCase().replace(/,/g, '').trim();
  const parts = lower.split(/\s+/);

  if (parts.length === 3) {
    const day = parts[0].replace(/\D/g, '').padStart(2, '0');
    const month = months[parts[1]];
    const year = parts[2].replace(/\D/g, '');
    if (day && month && year.length === 4) {
      return `${year}-${month}-${day}`;
    }
  }

  return 'Unknown';
}

function getProcessingDate() {
  const d = $execution?.startTime ? new Date($execution.startTime) : new Date();
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

function getQuarter(month) {
  if (month >= 1 && month <= 3) return 'Q1';
  if (month >= 4 && month <= 6) return 'Q2';
  if (month >= 7 && month <= 9) return 'Q3';
  if (month >= 10 && month <= 12) return 'Q4';
  return 'Unknown';
}

function extractDateParts(dateStr) {
  if (!dateStr || !/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
    return {
      year: 'Unknown',
      month: 0,
      day: 'Unknown'
    };
  }

  return {
    year: dateStr.slice(0, 4),
    month: Number(dateStr.slice(5, 7)),
    day: dateStr.slice(8, 10)
  };
}

// ===== Read model raw response =====
let raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.content?.[0]?.text ||
  $json.content?.parts?.[0]?.text ||
  '';

raw = String(raw).replace(/```json|```/g, '').trim();

if (!raw) {
  throw new Error('Model returned empty text');
}

const data = JSON.parse(raw);

// ===== Normalize extracted fields =====
const documentType = clean(data.documentType || data.invoiceType || 'Unknown');
const shopName = clean(data.shopName || 'Unknown');
const documentNumber = clean(data.documentNumber || data.invoiceNumber || 'Unknown');
const amount = clean(normalizeAmount(data.amount));
const currency = clean(normalizeCurrency(data.currency));
const itemDescription = clean(data.itemDescription || 'Unknown');

// ===== documentDate with fallback =====
let rawDate = data.documentDate || data.invoiceDate || '';
let normalizedDate = normalizeDate(rawDate);

if (!normalizedDate || normalizedDate === 'Unknown') {
  normalizedDate = getProcessingDate();
}

const documentDate = clean(normalizedDate);

// ===== detect extension =====
let extension = 'pdf';

if ($binary?.attachment_0?.fileExtension) {
  extension = String($binary.attachment_0.fileExtension).toLowerCase();
} else if (
  $binary?.attachment_0?.mimeType === 'text/csv' ||
  $binary?.attachment_0?.mimeType === 'application/vnd.ms-excel'
) {
  extension = 'csv';
}

// ===== build final file name =====
const finalFileName = `${documentDate}_${documentType}_${shopName}_${documentNumber}_${amount}_${currency}_${itemDescription}.${extension}`;
const duplicateKey = `${documentType}_${documentDate}_${shopName}_${documentNumber}_${amount}_${currency}`;

// ===== routing fields =====
const dateParts = extractDateParts(documentDate);
const year = dateParts.year;
const month = dateParts.month;
const quarter = getQuarter(month);
const quarterYear = `${quarter}_${year}`;
const targetFolderKey = `${quarter}_${year}_${documentType}`;

// ===== return =====
return {
  json: {
    ...$json,
    ...data,
    documentType,
    documentDate,
    shopName,
    documentNumber,
    amount,
    currency,
    itemDescription,
    finalFileName,
    duplicateKey,
    fileExtension: extension,
    year,
    month,
    quarter,
    quarterYear,
    targetFolderKey
  },
  binary: $binary
};

